// ─── Types ────────────────────────────────────────────────────────────────────

export interface VocabWord {
  word: string
  pronunciation: string
  translation_ar: string
  emoji: string
  example: string
}
export interface Sentence   { english: string; arabic: string }
export interface DialogueLine { speaker: 'A' | 'B'; name: string; english: string; arabic: string }
export type ExType = 'mc' | 'fill' | 'en_ar' | 'ar_en' | 'order'
export interface Exercise {
  type: ExType; tip_ar: string; prompt: string
  options: string[]; correct: number
  words?: string[]; answer?: string[]
}
export interface LessonData {
  id: string; title: string; title_ar: string
  level: string; emoji: string; color: string
  vocab: VocabWord[]
  sentences: Sentence[]   // simple sentences
  natural: Sentence[]     // natural / fuller sentences
  dialogue: DialogueLine[]
  exercises: Exercise[]
}

